const crypto = require('crypto');
const secret = $env.FATHOM_WEBHOOK_SECRET || '';
if (secret) {
  const sig = $input.first().json.headers?.['x-fathom-signature'] || '';
  const body = JSON.stringify($input.first().json.body);
  const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(body).digest('hex');
  if (sig !== expected) throw new Error('Invalid HMAC signature');
}
return $input.all();

