const responseText = $input.first().json.choices?.[0]?.message?.content || '';
const callId = $('Insert Call').first().json[0].id;
const validTypes = ['discovery', 'ads_intro', 'launch', 'follow_up', 'team', 'other'];
let classification;
try { classification = JSON.parse(responseText); } catch (e) { classification = { call_type: 'other', confidence: 0, reasoning: 'parse error' }; }
if (!validTypes.includes(classification.call_type)) classification.call_type = 'other';
return [{ json: { ...classification, call_id: callId } }];

const call = $('Get Call Data').first().json[0];
const rubricRow = $('Get Active Rubric').first().json[0];
if (!call) throw new Error('Call not found');
if (!rubricRow) throw new Error('No active rubric');
const rules = rubricRow.content;
const callId = call.id;
const callType = call.call_type || 'other';
const findings = [];
const segments = Array.isArray(call.transcript_segments) ? call.transcript_segments : [];
let repLabel = 'host';
if (segments.length > 0) { const speakers = [...new Set(segments.map(s => s.speaker).filter(Boolean))]; if (!speakers.includes('host') && speakers.length > 0) repLabel = speakers[0]; }
const repSegments = segments.filter(s => s.speaker === repLabel);
const repText = repSegments.map(s => s.text || s.content || '').join(' ');
for (const banned of (rules.banned_words || [])) {
  const appliesTo = banned.applies_to_call_types || [];
  if (appliesTo.length > 0 && !appliesTo.includes(callType)) continue;
  const word = banned.word.toLowerCase();
  const regex = new RegExp('\\b' + word + '\\b', 'gi');
  const matches = repText.match(regex) || [];
  if (matches.length > 0) {
    const contextSnippets = repSegments.filter(s => (s.text || s.content || '').toLowerCase().includes(word)).slice(0, 5).map(s => ({ text: s.text || s.content, timestamp: s.start_time }));
    const suggestion = `Do not use the word "${banned.word}" on ${appliesTo.join(' or ')} calls. ${banned.reason || ''} You said it ${matches.length} time${matches.length > 1 ? 's' : ''} on this call.`;
    findings.push({ call_id: callId, rule_key: 'banned_word_' + word, value: { word, count: matches.length, suggestion }, severity: banned.severity || 'critical', context_snippets: contextSnippets });
  }
}
for (const filler of (rules.filler_words || [])) {
  const word = filler.word.toLowerCase();
  const regex = new RegExp('\\b' + word + '\\b', 'gi');
  const matches = repText.match(regex) || [];
  const count = matches.length;
  const threshold = filler.threshold_per_call || 5;
  if (count > threshold) {
    const contextSnippets = repSegments.filter(s => (s.text || s.content || '').toLowerCase().includes(word)).slice(0, 3).map(s => ({ text: s.text || s.content, timestamp: s.start_time }));
    const suggestion = `Reduce use of "${word}". You said it ${count} times (target: under ${threshold}). Replace with a deliberate pause.`;
    findings.push({ call_id: callId, rule_key: 'filler_word_' + word, value: { word, count, threshold, suggestion }, severity: filler.severity || 'warning', context_snippets: contextSnippets });
  }
}
const totalSeconds = call.duration_seconds || 0;
if (rules.talk_ratio && totalSeconds > 0 && segments.length > 0) {
  const repSeconds = repSegments.reduce((sum, s) => sum + Math.max(0, (s.end_time || 0) - (s.start_time || 0)), 0);
  const repPercentage = Math.round((repSeconds / totalSeconds) * 100);
  const maxPercentage = rules.talk_ratio.max_rep_percentage || 60;
  if (repPercentage > maxPercentage) {
    const suggestion = `You spoke for ${repPercentage}% of this call — target is under ${maxPercentage}%. Ask a question, then stop talking.`;
    findings.push({ call_id: callId, rule_key: 'talk_ratio', value: { rep_percentage: repPercentage, max_allowed: maxPercentage, suggestion }, severity: rules.talk_ratio.severity || 'warning', context_snippets: [] });
  }
}
if (findings.length === 0) return [{ json: { __no_findings: true, call_id: callId } }];
return findings.map(f => ({ json: f }));

