const responseText = $input.first().json.choices?.[0]?.message?.content || '';
const callId = $('Parse Classification').first().json.call_id;
const rubric = $('Get Active Rubric').first().json[0];
let scorecard;
try { scorecard = JSON.parse(responseText); } catch (e) { throw new Error('Failed to parse scorecard: ' + responseText.substring(0, 300)); }
if (typeof scorecard.overall_score !== 'number') scorecard.overall_score = 0;
if (!Array.isArray(scorecard.strengths)) scorecard.strengths = [];
if (!Array.isArray(scorecard.improvements)) scorecard.improvements = [];
if (!scorecard.summary) scorecard.summary = '';
const allEvidence = [
  ...scorecard.strengths.filter(s => s.evidence_quote).map(s => ({ criterion_key: s.criterion, quote: s.evidence_quote, timestamp_seconds: s.timestamp_seconds || null })),
  ...scorecard.improvements.filter(s => s.evidence_quote).map(s => ({ criterion_key: s.criterion, quote: s.evidence_quote, timestamp_seconds: s.timestamp_seconds || null }))
];
return [{ json: { call_id: callId, rubric_id: rubric.id, overall_score: Math.round(scorecard.overall_score * 10) / 10, summary: scorecard.summary, strengths: scorecard.strengths, improvements: scorecard.improvements, llm_model: 'llama-3.3-70b-versatile', all_evidence: allEvidence } }];

const scorecardId = $('Insert Scorecard').first().json[0].id;
const allEvidence = $('Parse Scorecard').first().json.all_evidence || [];
if (allEvidence.length === 0) return [{ json: { __skip_evidence: true } }];
const evidenceRows = allEvidence.map(e => ({ scorecard_id: scorecardId, criterion_key: e.criterion_key, quote: e.quote, timestamp_seconds: e.timestamp_seconds }));
return [{ json: { evidence: evidenceRows } }];

