const responseText = $input.first().json.choices?.[0]?.message?.content || '';
const callId = $('Parse Classification').first().json.call_id;
let summary;
try { summary = JSON.parse(responseText); } catch (e) { throw new Error('Failed to parse meeting summary: ' + responseText.substring(0, 300)); }
if (!Array.isArray(summary.key_points)) summary.key_points = [];
if (!Array.isArray(summary.decisions_made)) summary.decisions_made = [];
if (!Array.isArray(summary.action_items)) summary.action_items = [];
if (!Array.isArray(summary.improvements_suggested)) summary.improvements_suggested = [];
if (!Array.isArray(summary.open_questions)) summary.open_questions = [];
if (!Array.isArray(summary.next_meeting_topics)) summary.next_meeting_topics = [];
return [{ json: { call_id: callId, summary } }];

const scorecardId = $('Store Meeting Scorecard').first().json[0].id;
const summary = $('Parse Meeting Summary').first().json.summary;
const evidenceRows = [
  ...(summary.action_items || []).map(item => ({ scorecard_id: scorecardId, criterion_key: 'action_item', quote: item.task + (item.owner ? ' — Owner: ' + item.owner : '') + (item.due ? ' — Due: ' + item.due : ''), timestamp_seconds: null })),
  ...(summary.decisions_made || []).map(d => ({ scorecard_id: scorecardId, criterion_key: 'decision', quote: d.decision + (d.decided_by ? ' (decided by ' + d.decided_by + ')' : ''), timestamp_seconds: null })),
  ...(summary.open_questions || []).map(q => ({ scorecard_id: scorecardId, criterion_key: 'open_question', quote: q, timestamp_seconds: null }))
];
if (evidenceRows.length === 0) return [{ json: { call_id: $('Parse Meeting Summary').first().json.call_id } }];
return [{ json: { evidence: evidenceRows, call_id: $('Parse Meeting Summary').first().json.call_id } }];

const participants = $('Get Participants').all();
const scorecard = $('Get Final Scorecard').first().json[0];
const callId = $('Parse Classification').first().json.call_id;
const portalUrl = ($env.PORTAL_URL || 'http://localhost:5173') + '/calls/' + callId;
if (!scorecard) return [{ json: { __no_scorecard: true } }];
const strengths = (scorecard.strengths || []).slice(0, 3);
const improvements = (scorecard.improvements || []).slice(0, 3);
const emailTargets = participants
  .filter(p => p.json.team_members && p.json.team_members.email)
  .map(p => ({ to: p.json.team_members.email, name: p.json.team_members.name || 'Team Member', overall_score: scorecard.overall_score, summary: scorecard.summary || '', strengths, improvements, portal_url: portalUrl }));
if (emailTargets.length === 0) return [{ json: { __no_recipients: true } }];
return emailTargets.map(t => ({ json: t }));
